import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {
    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String basePath = "/home/user/docs/";

        // Use Paths.get() to safely resolve the file path
        File file = Paths.get(basePath, userInput).toFile();

        // Validate if the resolved file path is within the base directory
        if (!file.getAbsolutePath().startsWith(basePath)) {
            System.out.println("Invalid file path");
            return;
        }

        try (FileInputStream fis = new FileInputStream(file)) {
            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

